import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  Box,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
} from "@mui/material";
import DashboardIcon from "@mui/icons-material/Dashboard";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import PersonIcon from "@mui/icons-material/Person";
import CalendarMonthIcon from "@mui/icons-material/CalendarMonth";
import AddIcon from "@mui/icons-material/Add";
import EditIcon from "@mui/icons-material/Edit";
import DeleteIcon from "@mui/icons-material/Delete";

const AdminDashboard = () => {
  const navigate = useNavigate();

  // Login protection
  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isAdminLoggedIn");
    if (isLoggedIn !== "true") navigate("/admin/login");
  }, [navigate]);

  const [activeTab, setActiveTab] = useState("dashboard");
  const [hospitals, setHospitals] = useState([]);
  const [doctors, setDoctors] = useState([]);
  const [appointments, setAppointments] = useState([]);

  const [openModal, setOpenModal] = useState(false);
  const [modalType, setModalType] = useState(""); // "addHospital", "editHospital", "addDoctor", "editDoctor"
  const [currentItem, setCurrentItem] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    location: "",
    specialty: "",
  });

  // Load from localStorage
  useEffect(() => {
    const savedHospitals = JSON.parse(localStorage.getItem("hospitals")) || [
      { id: 1, name: "City Care Hospital", location: "Kathmandu" },
      { id: 2, name: "Green Valley Medical Center", location: "Pokhara" },
    ];
    const savedDoctors = JSON.parse(localStorage.getItem("doctors")) || [
      { id: 101, name: "Dr. Aashish Das", specialty: "Cardiology" },
      { id: 102, name: "Dr. Neha Sharma", specialty: "Neurology" },
    ];
    const savedAppointments =
      JSON.parse(localStorage.getItem("appointments")) || [];

    setHospitals(savedHospitals);
    setDoctors(savedDoctors);
    setAppointments(savedAppointments);
  }, []);

  // Save to localStorage
  useEffect(() => {
    localStorage.setItem("hospitals", JSON.stringify(hospitals));
    localStorage.setItem("doctors", JSON.stringify(doctors));
    localStorage.setItem("appointments", JSON.stringify(appointments));
  }, [hospitals, doctors, appointments]);

  // Modal handlers
  const openAddModal = (type) => {
    setModalType(type);
    setCurrentItem(null);
    setFormData({ name: "", location: "", specialty: "" });
    setOpenModal(true);
  };

  const openEditModal = (type, item) => {
    setModalType(type);
    setCurrentItem(item);
    setFormData({
      name: item.name,
      location: item.location || "",
      specialty: item.specialty || "",
    });
    setOpenModal(true);
  };

  const handleSave = () => {
    if (!formData.name) return alert("Name is required");

    if (modalType === "addHospital" || modalType === "editHospital") {
      if (modalType === "addHospital") {
        setHospitals([
          ...hospitals,
          { id: Date.now(), name: formData.name, location: formData.location },
        ]);
      } else {
        setHospitals(
          hospitals.map((h) =>
            h.id === currentItem.id ? { ...h, ...formData } : h,
          ),
        );
      }
    } else if (modalType === "addDoctor" || modalType === "editDoctor") {
      if (modalType === "addDoctor") {
        setDoctors([
          ...doctors,
          {
            id: Date.now(),
            name: formData.name,
            specialty: formData.specialty,
          },
        ]);
      } else {
        setDoctors(
          doctors.map((d) =>
            d.id === currentItem.id ? { ...d, ...formData } : d,
          ),
        );
      }
    }
    setOpenModal(false);
  };

  const handleDelete = (type, id) => {
    if (type === "hospital") setHospitals(hospitals.filter((h) => h.id !== id));
    if (type === "doctor") setDoctors(doctors.filter((d) => d.id !== id));
  };

  return (
    <Box sx={{ display: "flex", minHeight: "100vh", bgcolor: "#f5f5f5" }}>
      {/* Sidebar */}
      <Box sx={{ width: 280, bgcolor: "#1a3c5e", color: "white", p: 3 }}>
        <Typography
          variant="h5"
          sx={{ mb: 4, fontWeight: "bold", textAlign: "center" }}
        >
          Admin Dashboard
        </Typography>

        <List>
          {["dashboard", "hospitals", "doctors", "appointments"].map((tab) => (
            <ListItem
              button
              key={tab}
              sx={{
                bgcolor: activeTab === tab ? "#2c5282" : "transparent",
                borderRadius: 1,
                mb: 1,
              }}
              onClick={() => setActiveTab(tab)}
            >
              <ListItemIcon sx={{ color: "white" }}>
                {tab === "dashboard" && <DashboardIcon />}
                {tab === "hospitals" && <LocalHospitalIcon />}
                {tab === "doctors" && <PersonIcon />}
                {tab === "appointments" && <CalendarMonthIcon />}
              </ListItemIcon>
              <ListItemText
                primary={tab.charAt(0).toUpperCase() + tab.slice(1)}
              />
            </ListItem>
          ))}
        </List>
      </Box>

      {/* Main Content */}
      <Box component="main" sx={{ flexGrow: 1, p: 4 }}>
        <Typography variant="h4" fontWeight="bold" gutterBottom>
          {activeTab === "dashboard" && "Admin Dashboard"}
          {activeTab === "hospitals" && "Manage Hospitals"}
          {activeTab === "doctors" && "Manage Doctors"}
          {activeTab === "appointments" && "Appointments"}
        </Typography>

        {/* Dashboard Tab */}
        {activeTab === "dashboard" && (
          <Grid container spacing={3}>
            <Grid item xs={12} sm={4}>
              <Card sx={{ bgcolor: "#e3f2fd" }}>
                <CardContent sx={{ textAlign: "center" }}>
                  <Typography variant="h3" color="primary">
                    {hospitals.length}
                  </Typography>
                  <Typography variant="h6">Total Hospitals</Typography>
                </CardContent>
              </Card>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Card sx={{ bgcolor: "#e8f5e9" }}>
                <CardContent sx={{ textAlign: "center" }}>
                  <Typography variant="h3" color="success.main">
                    {doctors.length}
                  </Typography>
                  <Typography variant="h6">Total Doctors</Typography>
                </CardContent>
              </Card>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Card sx={{ bgcolor: "#fff3e0" }}>
                <CardContent sx={{ textAlign: "center" }}>
                  <Typography variant="h3" color="warning.main">
                    {appointments.length}
                  </Typography>
                  <Typography variant="h6">Total Appointments</Typography>
                </CardContent>
              </Card>
            </Grid>
          </Grid>
        )}

        {/* Hospitals Tab */}
        {activeTab === "hospitals" && (
          <Paper sx={{ p: 3 }}>
            <Box
              sx={{ display: "flex", justifyContent: "space-between", mb: 3 }}
            >
              <Typography variant="h6" fontWeight="bold">
                Manage Hospitals
              </Typography>
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => openAddModal("addHospital")}
              >
                Add Hospital
              </Button>
            </Box>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Hospital Name</TableCell>
                    <TableCell>Location</TableCell>
                    <TableCell align="right">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {hospitals.map((h) => (
                    <TableRow key={h.id}>
                      <TableCell>{h.name}</TableCell>
                      <TableCell>{h.location}</TableCell>
                      <TableCell align="right">
                        <Button
                          size="small"
                          startIcon={<EditIcon />}
                          onClick={() => openEditModal("editHospital", h)}
                        >
                          Edit
                        </Button>
                        <Button
                          size="small"
                          color="error"
                          onClick={() => handleDelete("hospital", h.id)}
                        >
                          Delete
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}

        {/* Doctors Tab */}
        {activeTab === "doctors" && (
          <Paper sx={{ p: 3 }}>
            <Box
              sx={{ display: "flex", justifyContent: "space-between", mb: 3 }}
            >
              <Typography variant="h6" fontWeight="bold">
                Manage Doctors
              </Typography>
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => openAddModal("addDoctor")}
              >
                Add Doctor
              </Button>
            </Box>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Doctor Name</TableCell>
                    <TableCell>Specialization</TableCell>
                    <TableCell align="right">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {doctors.map((d) => (
                    <TableRow key={d.id}>
                      <TableCell>{d.name}</TableCell>
                      <TableCell>{d.specialty}</TableCell>
                      <TableCell align="right">
                        <Button
                          size="small"
                          startIcon={<EditIcon />}
                          onClick={() => openEditModal("editDoctor", d)}
                        >
                          Edit
                        </Button>
                        <Button
                          size="small"
                          color="error"
                          onClick={() => handleDelete("doctor", d.id)}
                        >
                          Delete
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}

        {/* Appointments Tab */}
        {activeTab === "appointments" && (
          <Paper sx={{ p: 4 }}>
            <Typography variant="h6" fontWeight="bold" gutterBottom>
              Recent Appointments
            </Typography>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Patient</TableCell>
                    <TableCell>Doctor</TableCell>
                    <TableCell>Hospital</TableCell>
                    <TableCell>Date</TableCell>
                    <TableCell>Status</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {appointments.map((a, i) => (
                    <TableRow key={i}>
                      <TableCell>{a.patient}</TableCell>
                      <TableCell>{a.doctor}</TableCell>
                      <TableCell>{a.hospital}</TableCell>
                      <TableCell>{a.date}</TableCell>
                      <TableCell>{getStatusChip(a.status)}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}
      </Box>

      {/* Modal for Add/Edit */}
      <Dialog
        open={openModal}
        onClose={() => setOpenModal(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>
          {modalType.includes("add") ? "Add" : "Edit"}{" "}
          {modalType.includes("Hospital") ? "Hospital" : "Doctor"}
        </DialogTitle>
        <DialogContent>
          <TextField
            fullWidth
            label="Name"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            sx={{ mt: 2 }}
          />
          {modalType.includes("Hospital") && (
            <TextField
              fullWidth
              label="Location"
              value={formData.location}
              onChange={(e) =>
                setFormData({ ...formData, location: e.target.value })
              }
              sx={{ mt: 2 }}
            />
          )}
          {modalType.includes("Doctor") && (
            <TextField
              fullWidth
              label="Specialty"
              value={formData.specialty}
              onChange={(e) =>
                setFormData({ ...formData, specialty: e.target.value })
              }
              sx={{ mt: 2 }}
            />
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenModal(false)}>Cancel</Button>
          <Button onClick={handleSave} variant="contained">
            Save
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default AdminDashboard;
